"use client";

import { useRef, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete, getRandomEncourage, triggerShake } from "@/lib/learningMessages";

const topicId = "data";

// ===== 题目类型 =====
interface QInput {
  type: "input";
  question: string;
  answer: string;
  unit?: string;
}
interface QChoice {
  type: "choice";
  question: string;
  options: { key: string; text: string }[];
  answer: string;
}
type Question = QInput | QChoice;

interface Scenario {
  id: string;
  icon: string;
  title: string;
  questions: Question[];
}

const SCENARIOS: Scenario[] = [
  {
    id: "books",
    icon: "📚",
    title: "统计家里的书",
    questions: [
      {
        type: "input",
        question: "数一数书架上的书：故事书 8 本、科普书 5 本、漫画书 3 本，一共有多少本？",
        answer: "16",
        unit: "本",
      },
    ],
  },
  {
    id: "weather",
    icon: "☀️",
    title: "一周天气",
    questions: [
      {
        type: "input",
        question: "这一周晴天有多少天？",
        answer: "4",
        unit: "天",
      },
      {
        type: "input",
        question: "晴天比雨天多几天？",
        answer: "3",
        unit: "天",
      },
    ],
  },
  {
    id: "birthday",
    icon: "🎂",
    title: "班级生日统计",
    questions: [
      {
        type: "choice",
        question: "哪个季节过生日的同学最多？",
        options: [
          { key: "A", text: "春" },
          { key: "B", text: "夏" },
          { key: "C", text: "秋" },
          { key: "D", text: "冬" },
        ],
        answer: "C",
      },
      {
        type: "input",
        question: "秋季比夏季多几人？",
        answer: "4",
        unit: "人",
      },
    ],
  },
];

// ===== 书架 SVG =====
function BookshelfSVG() {
  const shelves = [
    { color: "var(--accent)", count: 8 },
    { color: "var(--primary)", count: 5 },
    { color: "var(--accent2)", count: 3 },
  ];
  return (
    <svg viewBox="0 0 240 220" className="mx-auto h-44" role="img" aria-label="书架上的书">
      <rect x="6" y="8" width="228" height="208" rx="10" fill="#B97D43" />
      <rect x="12" y="14" width="216" height="199" rx="6" fill="#F3DEB8" />
      {shelves.map((sh, si) => {
        const bandTop = 18 + si * 64;
        const boardY = bandTop + 58;
        const bookW = 16;
        const gap = 3;
        const totalW = sh.count * bookW + (sh.count - 1) * gap;
        const startX = 12 + (216 - totalW) / 2;
        return (
          <g key={si}>
            {Array.from({ length: sh.count }, (_, i) => {
              const h = 46 - (i % 3) * 4;
              const x = startX + i * (bookW + gap);
              const y = boardY - h - 3;
              return (
                <rect key={i} x={x} y={y} width={bookW} height={h} rx={3} fill={sh.color} />
              );
            })}
            <rect x="12" y={boardY} width="216" height="7" rx="3" fill="#8B5A2B" />
          </g>
        );
      })}
    </svg>
  );
}

function BooksLegend() {
  const items = [
    { color: "var(--accent)", label: "故事书 8 本" },
    { color: "var(--primary)", label: "科普书 5 本" },
    { color: "var(--accent2)", label: "漫画书 3 本" },
  ];
  return (
    <div className="mt-3 flex flex-wrap justify-center gap-3 text-xs text-[var(--text-secondary)]">
      {items.map((it) => (
        <span key={it.label} className="inline-flex items-center gap-1.5">
          <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: it.color }} />
          {it.label}
        </span>
      ))}
    </div>
  );
}

// ===== 一周天气 SVG =====
function SunIcon({ cx, cy }: { cx: number; cy: number }) {
  const rays = Array.from({ length: 8 }, (_, i) => {
    const a = (i * Math.PI) / 4;
    return {
      x1: cx + Math.cos(a) * 13,
      y1: cy + Math.sin(a) * 13,
      x2: cx + Math.cos(a) * 19,
      y2: cy + Math.sin(a) * 19,
    };
  });
  return (
    <g>
      {rays.map((r, i) => (
        <line
          key={i}
          x1={r.x1}
          y1={r.y1}
          x2={r.x2}
          y2={r.y2}
          stroke="#FBBF24"
          strokeWidth={2.5}
          strokeLinecap="round"
        />
      ))}
      <circle cx={cx} cy={cy} r={9} fill="#FBBF24" />
    </g>
  );
}

function CloudIcon({ cx, cy }: { cx: number; cy: number }) {
  return (
    <g fill="#94A3B8">
      <ellipse cx={cx} cy={cy} rx={16} ry={9} />
      <circle cx={cx - 8} cy={cy - 3} r={7} />
      <circle cx={cx + 7} cy={cy - 4} r={8} />
    </g>
  );
}

function RainIcon({ cx, cy }: { cx: number; cy: number }) {
  return (
    <g>
      <g fill="#64748B">
        <ellipse cx={cx} cy={cy - 6} rx={14} ry={7} />
        <circle cx={cx - 7} cy={cy - 8} r={6} />
        <circle cx={cx + 6} cy={cy - 9} r={7} />
      </g>
      <g fill="#38BDF8">
        <ellipse cx={cx - 6} cy={cy + 6} rx={2} ry={4} />
        <ellipse cx={cx} cy={cy + 9} rx={2} ry={4} />
        <ellipse cx={cx + 6} cy={cy + 6} rx={2} ry={4} />
      </g>
    </g>
  );
}

function WeekWeatherSVG() {
  const days = [
    { type: "sun", label: "一" },
    { type: "sun", label: "二" },
    { type: "cloud", label: "三" },
    { type: "cloud", label: "四" },
    { type: "rain", label: "五" },
    { type: "sun", label: "六" },
    { type: "sun", label: "日" },
  ] as const;
  const cellW = 32;
  const iconY = 30;
  return (
    <svg viewBox="0 0 240 70" className="mx-auto h-20" role="img" aria-label="一周天气">
      {days.map((d, i) => {
        const cx = 20 + i * cellW;
        return (
          <g key={i}>
            <rect x={cx - 15} y={6} width={30} height={58} rx={8} fill="var(--bg-soft)" />
            {d.type === "sun" && <SunIcon cx={cx} cy={iconY} />}
            {d.type === "cloud" && <CloudIcon cx={cx} cy={iconY} />}
            {d.type === "rain" && <RainIcon cx={cx} cy={iconY} />}
            <text
              x={cx}
              y={56}
              textAnchor="middle"
              fontSize="11"
              fill="var(--text-secondary)"
              fontWeight="bold"
            >
              {d.label}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

// ===== 蛋糕 SVG =====
function CakeSVG() {
  const drips1 = Array.from({ length: 7 }, (_, i) => 36 + i * 20);
  const drips2 = Array.from({ length: 5 }, (_, i) => 61 + i * 20);
  const candles = [75, 100, 125];
  return (
    <svg viewBox="0 0 200 175" className="mx-auto h-32" role="img" aria-label="生日蛋糕">
      <ellipse cx="100" cy="162" rx="82" ry="8" fill="#E2E8F0" />
      {/* 底层 */}
      <rect x="28" y="98" width="144" height="58" rx="10" fill="var(--accent)" />
      <rect x="28" y="98" width="144" height="16" rx="8" fill="var(--accent-light)" />
      {drips1.map((x, i) => (
        <circle key={`d1-${i}`} cx={x} cy="114" r="6" fill="var(--accent-light)" />
      ))}
      {/* 上层 */}
      <rect x="56" y="58" width="88" height="44" rx="8" fill="var(--primary)" />
      <rect x="56" y="58" width="88" height="13" rx="6" fill="var(--primary-light)" />
      {drips2.map((x, i) => (
        <circle key={`d2-${i}`} cx={x} cy="71" r="5" fill="var(--primary-light)" />
      ))}
      {/* 蜡烛 */}
      {candles.map((x, i) => (
        <g key={`c-${i}`}>
          <rect x={x - 2} y="34" width="4" height="24" rx="2" fill="#FBBF24" />
          <ellipse cx={x} cy="30" rx="3.5" ry="6" fill="#FB923C" />
        </g>
      ))}
    </svg>
  );
}

// ===== 班级生日条形图 =====
function BirthdayBars() {
  const seasons = [
    { name: "春", count: 6, color: "var(--accent2)" },
    { name: "夏", count: 4, color: "var(--primary)" },
    { name: "秋", count: 8, color: "var(--accent3)" },
    { name: "冬", count: 5, color: "var(--accent)" },
  ];
  const max = 8;
  return (
    <div className="flex items-end justify-center gap-4" style={{ height: 130 }}>
      {seasons.map((s) => (
        <div key={s.name} className="flex flex-col items-center gap-1">
          <span className="text-sm font-bold text-[var(--text)]">{s.count} 人</span>
          <div
            className="w-11 rounded-t-lg transition-all duration-300"
            style={{ height: `${(s.count / max) * 80}px`, backgroundColor: s.color }}
          />
          <span className="text-xs font-medium text-[var(--text-secondary)]">{s.name}</span>
        </div>
      ))}
    </div>
  );
}

