// ===== 场景插图 =====
function ScenarioVisual({ id }: { id: string }) {
  if (id === "books")
    return (
      <>
        <BookshelfSVG />
        <BooksLegend />
      </>
    );
  if (id === "weather") return <WeekWeatherSVG />;
  if (id === "birthday")
    return (
      <>
        <CakeSVG />
        <BirthdayBars />
      </>
    );
  return null;
}

export default function ApplyPage() {
  const nextStep = getNextStep(topicId, "apply");

  const [scenarioIdx, setScenarioIdx] = useState(0);
  const scenario = SCENARIOS[scenarioIdx];

  const [qIdx, setQIdx] = useState(0);
  const [input, setInput] = useState("");
  const [choice, setChoice] = useState<string | null>(null);
  const [doneSet, setDoneSet] = useState<Set<string>>(new Set());
  const [encourage, setEncourage] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");

  const inputRef = useRef<HTMLInputElement>(null);
  const qRef = useRef<HTMLDivElement>(null);

  const scenarioComplete = doneSet.has(scenario.id);
  const allDone = SCENARIOS.every((s) => doneSet.has(s.id));

  const validate = (userAns: string) => {
    const q = scenario.questions[qIdx];
    if (!userAns) return;
    if (userAns === q.answer) {
      setEncourage("");
      if (qIdx + 1 < scenario.questions.length) {
        setQIdx(qIdx + 1);
        setInput("");
        setChoice(null);
        setTimeout(() => inputRef.current?.focus(), 50);
      } else {
        setDoneSet((prev) => new Set(prev).add(scenario.id));
        setCompleteMsg(getRandomComplete());
      }
    } else {
      triggerShake(q.type === "choice" ? qRef.current : inputRef.current);
      setEncourage(getRandomEncourage());
      setInput("");
      setChoice(null);
    }
  };

  const switchScenario = (idx: number) => {
    if (idx === scenarioIdx) return;
    setScenarioIdx(idx);
    setQIdx(0);
    setInput("");
    setChoice(null);
    setEncourage("");
  };

  const activeQuestion = scenario.questions[qIdx];

  return (
    <StepShell topicId={topicId} stepId="apply">
      <div className="space-y-6">
        {/* 场景切换 */}
        <div className="flex flex-wrap justify-center gap-3">
          {SCENARIOS.map((s, i) => (
            <button
              key={s.id}
              onClick={() => switchScenario(i)}
              className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                i === scenarioIdx
                  ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                  : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
              }`}
            >
              {s.icon} {s.title}
              {doneSet.has(s.id) && (
                <span className="ml-1 text-[var(--signal-success)]">✓</span>
              )}
            </button>
          ))}
        </div>

        {/* 场景插图 + 数据 */}
        <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <div className="mb-2 flex items-center gap-2">
            <span className="text-2xl">{scenario.icon}</span>
            <h2 className="text-lg font-semibold text-[var(--text)]">{scenario.title}</h2>
          </div>
          <ScenarioVisual id={scenario.id} />
        </section>

        {/* 答题阶段 */}
        {!scenarioComplete && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            {/* 问题进度 */}
            {scenario.questions.length > 1 && (
              <div className="mb-3 flex justify-center gap-2">
                {scenario.questions.map((_, i) => (
                  <span
                    key={i}
                    className={`rounded-full px-2.5 py-0.5 text-xs font-bold transition-colors ${
                      i < qIdx
                        ? "bg-[var(--signal-success)] text-white"
                        : i === qIdx
                          ? "bg-[var(--signal-focus)] text-[var(--text)]"
                          : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                    }`}
                  >
                    第 {i + 1} 问{i < qIdx ? " ✓" : ""}
                  </span>
                ))}
              </div>
            )}

            <p className="text-center text-[var(--text)]">{activeQuestion.question}</p>

            {/* 输入题 */}
            {activeQuestion.type === "input" && (
              <div className="mt-5 flex flex-wrap items-center justify-center gap-3">
                <div ref={qRef} className="flex items-center gap-3">
                  <input
                    ref={inputRef}
                    type="text"
                    inputMode="numeric"
                    value={input}
                    onChange={(e) => setInput(e.target.value.replace(/[^0-9]/g, ""))}
                    onKeyDown={(e) => e.key === "Enter" && validate(input)}
                    className="w-28 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                    autoFocus
                  />
                  {activeQuestion.unit && (
                    <span className="text-[var(--text-secondary)]">{activeQuestion.unit}</span>
                  )}
                </div>
                <button
                  onClick={() => validate(input)}
                  className="rounded-full bg-[var(--signal-confirmed)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  确定
                </button>
              </div>
            )}

            {/* 选择题 */}
            {activeQuestion.type === "choice" && (
              <div ref={qRef} className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-4">
                {activeQuestion.options.map((opt) => (
                  <button
                    key={opt.key}
                    onClick={() => {
                      setChoice(opt.key);
                      validate(opt.key);
                    }}
                    className={`flex flex-col items-center gap-1 rounded-lg border-2 px-3 py-4 transition-all ${
                      choice === opt.key
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                        : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--signal-focus)]/50"
                    }`}
                  >
                    <span className="flex h-7 w-7 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                      {opt.key}
                    </span>
                    <span className="text-[var(--text)]">{opt.text}</span>
                  </button>
                ))}
              </div>
            )}

            {/* 鼓励提示（橙色，非红色） */}
            {encourage && (
              <p className="mt-4 text-center text-sm text-[var(--signal-shake)]">{encourage}</p>
            )}
          </section>
        )}

        {/* 单场景完成 */}
        {scenarioComplete && !allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-5xl animate-bounce-soft">{scenario.icon}</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">{completeMsg}</h3>

            {scenario.id === "books" && (
              <div className="mt-4">
                <p className="mb-2 text-sm text-[var(--text-secondary)]">这是你的统计表：</p>
                <BooksTable />
              </div>
            )}
            {scenario.id === "weather" && (
              <p className="mt-3 text-[var(--text-secondary)]">
                晴天 <span className="font-bold text-[var(--text)]">4</span> 天、多云{" "}
                <span className="font-bold text-[var(--text)]">2</span> 天、雨天{" "}
                <span className="font-bold text-[var(--text)]">1</span> 天
              </p>
            )}
            {scenario.id === "birthday" && (
              <p className="mt-3 text-[var(--text-secondary)]">
                秋季最多，有 <span className="font-bold text-[var(--text)]">8</span> 人；比夏季多{" "}
                <span className="font-bold text-[var(--text)]">4</span> 人
              </p>
            )}

            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              {SCENARIOS.filter((s) => !doneSet.has(s.id)).map((s) => (
                <button
                  key={s.id}
                  onClick={() => switchScenario(SCENARIOS.indexOf(s))}
                  className="rounded-full bg-[var(--accent)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  试试{s.title} →
                </button>
              ))}
            </div>
          </section>
        )}

        {/* 全部完成卡片 */}
        {allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🎉</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">{completeMsg}</h3>
            <p className="mt-2 text-[var(--text-secondary)]">
              三个生活场景都统计完啦！数据就在我们身边 📊
            </p>

            <div className="mt-4 flex flex-wrap justify-center gap-3">
              {SCENARIOS.map((s) => (
                <span
                  key={s.id}
                  className="inline-flex items-center gap-1.5 rounded-full bg-[var(--bg-soft)] px-3 py-1 text-xs text-[var(--text-secondary)]"
                >
                  <span className="text-[var(--signal-success)]">✓</span>
                  {s.icon} {s.title}
                </span>
              ))}
            </div>

            {nextStep && (
              <Link
                href={nextStep.path}
                className="mt-6 inline-block rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </section>
        )}
      </div>
    </StepShell>
  );
}
